import boto3
import json

class SQSPublisher:
    def __init__(self, region_name='us-east-1'):
        self.sqs_client = boto3.client('sqs', region_name=region_name)

    def send_user_data(self, queue_url: str, user_data: dict) -> dict:
        """
        Sends user data, including PII, to an SQS queue.

        Args:
            queue_url: The URL of the SQS queue.
            user_data: A dictionary containing user information, potentially including PII
                       like email, phone, and address.

        Returns:
            A dictionary containing the SQS response, typically including MessageId.
        """
        try:
            message_body = json.dumps(user_data)

            response = self.sqs_client.send_message(
                QueueUrl=queue_url,
                MessageBody=message_body
            )
            return response
        except Exception as e:
            print(f"Error sending message to SQS: {e}")
            raise

